export declare const GET_USER_STATS_QUERY = "\n  query($login: String!) {\n    user(login: $login) {\n      login\n      name\n      avatarUrl\n      bio\n      company\n      location\n      email\n      twitterUsername\n      websiteUrl\n      followers { totalCount }\n      following { totalCount }\n      repositories(first: 100, ownerAffiliations: OWNER, orderBy: {field: STARGAZERS, direction: DESC}) {\n        totalCount\n        nodes {\n          stargazerCount\n        }\n      }\n      contributionsCollection {\n        contributionCalendar {\n          totalContributions\n          weeks {\n            contributionDays {\n              contributionCount\n              date\n              color\n            }\n          }\n        }\n      }\n    }\n  }\n";
